using System.Collections; using System.Collections.Generic; using UnityEngine; using UnityEngine.EventSystems;  public class ItemSlot : MonoBehaviour, IDropHandler {     public LevelManager levelManager;     public TipoPeca tipoPeca;      [Header("Rejeicao")]     public float rejeicaoDuracao = 0.5f;      [Header("Grid de Comidas")]     public float gridSpacing = 120f;      private List<DragDrop> pecasNoSlot = new List<DragDrop>();      public void OnDrop(PointerEventData eventData)     {         if (eventData.pointerDrag == null) return;          var peca = eventData.pointerDrag.GetComponent<DragDrop>();         if (peca == null) return;          // rejeita tag errada         if (eventData.pointerDrag.tag != gameObject.tag)         {             RejeitarPeca(peca);             return;         }          // rejeita tipo de peca errado pro slot         if (peca.tipoPeca != tipoPeca)         {             RejeitarPeca(peca);             return;         }          switch (tipoPeca)         {             case TipoPeca.Numero:                 if (pecasNoSlot.Count > 0)                 {                     RejeitarPeca(peca);                     break;                 }                 EncaixarPeca(peca);                 break;              case TipoPeca.Comida:                 TentarAdicionarComida(peca);                 break;         }     }      private void TentarAdicionarComida(DragDrop peca)     {         if (pecasNoSlot.Count > 0 && pecasNoSlot[0].valorComida != peca.valorComida)         {             Debug.Log("Tipo de comida errado, expulsando todas!");             ExpulsarTodasPecas();             RejeitarPeca(peca);             return;         }          //if (pecasNoSlot.Count >= levelManager.number)         //{         //    Debug.Log("Slot cheio!");         //    RejeitarPeca(peca);         //    return;         //}          EncaixarPeca(peca);         Debug.Log($"Comida adicionada: {pecasNoSlot.Count}/{levelManager.number}");          if (pecasNoSlot.Count == levelManager.number)         {             Debug.Log("Combinacao correta!");         }     }      private void EncaixarPeca(DragDrop peca)     {         int number = Random.Range(0, 6);         if (number < 3)         {             SoundManager.Instance?.Play("Drop_1");         } else         {             SoundManager.Instance?.Play("Drop_2");         }          pecasNoSlot.Add(peca);         peca.GetComponent<CanvasGroup>().blocksRaycasts = false;         peca.MarcarAceitoNoSlot();          RectTransform slotRT = GetComponent<RectTransform>();         RectTransform pecaRT = peca.GetComponent<RectTransform>();         pecaRT.SetParent(slotRT, true);          // reset do anchoredPosition logo apos o SetParent: worldPositionStays=true         // preserva a posicao em espaco de mundo, mas o anchoredPosition recalculado         // em relacao ao novo parent pode vir com um offset grande (dependendo do         // pivot/escala/tamanho do slot vs. o parent anterior), fazendo a peca         // "saltar" visualmente para o centro da tela antes da coroutine assentar         // ela no lugar certo. Zerando aqui, toda peca comeca a animar a partir         // do centro do slot, que e o ponto de partida correto tanto pro caso         // fixo (Numero) quanto pro grid (Comida).         pecaRT.anchoredPosition = Vector2.zero;          if (tipoPeca != TipoPeca.Numero)         {             OrganizarGrid();         }     }      public bool EstaCompleto()     {         if (tipoPeca == TipoPeca.Numero)             return pecasNoSlot.Count == 1;         else             return pecasNoSlot.Count == levelManager.number;     }      public void LimparSlot()     {         foreach (var p in pecasNoSlot)             if (p != null) Destroy(p.gameObject);         pecasNoSlot.Clear();     }      private void OrganizarGrid()     {         int colunas = 3;          for (int i = 0; i < pecasNoSlot.Count; i++)         {             int col = i % colunas;             int row = i / colunas;              int totalColunas = Mathf.Min(pecasNoSlot.Count, colunas);             int totalLinhas = Mathf.CeilToInt(pecasNoSlot.Count / (float)colunas);              float offsetX = (totalColunas - 1) * gridSpacing / 2f;             float offsetY = (totalLinhas - 1) * gridSpacing / 2f;              Vector2 posAlvo = new Vector2(                 col * gridSpacing - offsetX,                 -(row * gridSpacing - offsetY)             );              StartCoroutine(MoverParaPosicao(pecasNoSlot[i].GetComponent<RectTransform>(), posAlvo, 0.2f));         }     }      private IEnumerator MoverParaPosicao(RectTransform rt, Vector2 destino, float duracao)     {         if (rt == null) yield break; // <- guard contra objeto destruido          Vector2 origem = rt.anchoredPosition;         float tempo = 0f;          while (tempo < duracao)         {             if (rt == null) yield break; // <- checa a cada frame tambem             tempo += Time.deltaTime;             float t = tempo / duracao;             t = t * t * (3f - 2f * t);             rt.anchoredPosition = Vector2.Lerp(origem, destino, t);             yield return null;         }          if (rt != null)             rt.anchoredPosition = destino;     }      private void RejeitarPeca(DragDrop peca)
    {
        SoundManager.Instance?.Play("Erro");
        peca.MarcarTratadoNoDrop();
        Canvas canvas = levelManager.canvas;
        peca.transform.SetParent(canvas.transform, true);
        peca.VoltarParaOrigem(rejeicaoDuracao, this);
    }

    public void ExpulsarTodasPecas()
    {
        foreach (var p in pecasNoSlot)
        {
            if (p == null) continue;
            p.MarcarTratadoNoDrop();
            Canvas canvas = levelManager.canvas;
            p.transform.SetParent(canvas.transform, true);
            p.VoltarParaOrigem(rejeicaoDuracao, this);
        }
        pecasNoSlot.Clear();
    }

    // chamado pelo DragDrop quando o jogador comeca a arrastar uma peca do slot
    public void RemoverDoSlot(DragDrop peca)
    {
        if (pecasNoSlot.Remove(peca))
        {
            peca.GetComponent<CanvasGroup>().blocksRaycasts = true;
            peca.transform.SetParent(levelManager.canvas.transform, true);
            OrganizarGrid();
        }
    } }